+        a: Vec<Vec<f64>>,
+        b: Vec<f64>,
+        assume_a: Option<FixtureMatrixAssumption>,
+        #[serde(default)]
+        lower: Option<bool>,
+        #[serde(default)]
+        transposed: Option<bool>,
+        #[serde(default)]
+        check_finite: Option<bool>,
+        expected: LinalgExpectedOutcome,
+    },
+    SolveTriangular {
+        case_id: String,
+        mode: RuntimeMode,
+        a: Vec<Vec<f64>>,
+        b: Vec<f64>,
+        trans: Option<FixtureTriangularTranspose>,
+        #[serde(default)]
+        lower: Option<bool>,
+        #[serde(default)]
+        unit_diagonal: Option<bool>,
+        #[serde(default)]
+        check_finite: Option<bool>,
+        expected: LinalgExpectedOutcome,
+    },
+    SolveBanded {
+        case_id: String,
+        mode: RuntimeMode,
+        l_and_u: [usize; 2],
+        ab: Vec<Vec<f64>>,
+        b: Vec<f64>,
+        #[serde(default)]
+        check_finite: Option<bool>,
+        expected: LinalgExpectedOutcome,
+    },
+    Inv {
+        case_id: String,
+        mode: RuntimeMode,
+        a: Vec<Vec<f64>>,
+        assume_a: Option<FixtureMatrixAssumption>,
+        #[serde(default)]
+        lower: Option<bool>,
+        #[serde(default)]
+        check_finite: Option<bool>,
+        expected: LinalgExpectedOutcome,
+    },
+    Det {
+        case_id: String,
+        mode: RuntimeMode,
+        a: Vec<Vec<f64>>,
+        #[serde(default)]
+        check_finite: Option<bool>,
+        expected: LinalgExpectedOutcome,
+    },
+    Lstsq {
+        case_id: String,
+        mode: RuntimeMode,
+        a: Vec<Vec<f64>>,
+        b: Vec<f64>,
+        #[serde(default)]
+        cond: Option<f64>,
+        #[serde(default)]
+        check_finite: Option<bool>,
+        expected: LinalgExpectedOutcome,
+    },
+    Pinv {
+        case_id: String,
+        mode: RuntimeMode,
+        a: Vec<Vec<f64>>,
+        #[serde(default)]
+        atol: Option<f64>,
+        #[serde(default)]
+        rtol: Option<f64>,
+        #[serde(default)]
+        check_finite: Option<bool>,
+        expected: LinalgExpectedOutcome,
+    },
+}
+
+impl LinalgCase {
+    fn case_id(&self) -> &str {
+        match self {
+            Self::Solve { case_id, .. }
+            | Self::SolveTriangular { case_id, .. }
+            | Self::SolveBanded { case_id, .. }
+            | Self::Inv { case_id, .. }
+            | Self::Det { case_id, .. }
+            | Self::Lstsq { case_id, .. }
+            | Self::Pinv { case_id, .. } => case_id,
+        }
+    }
+
+    fn expected(&self) -> &LinalgExpectedOutcome {
+        match self {
+            Self::Solve { expected, .. }
+            | Self::SolveTriangular { expected, .. }
+            | Self::SolveBanded { expected, .. }
+            | Self::Inv { expected, .. }
+            | Self::Det { expected, .. }
+            | Self::Lstsq { expected, .. }
+            | Self::Pinv { expected, .. } => expected,
+        }
+    }
+}
